    class PriceChangeCalculator:
        def __init__(self, data, weights, dimensions):
            """
            Inicializa a classe com as tabelas principais.
            
            :param data: DataFrame com as variações mensais (m/m) dos subitens.
            :param weights: DataFrame com os pesos dos subitens.
            :param dimensions: DataFrame com as dimensões dos subitens (e.g., Grupo, Subgrupo).
            """
            self.data = data
            self.weights = weights
            self.dimensions = dimensions

        def calculate_dimension_variation(self, dimension_name, dimension_value):
            """
            Calcula a variação m/m para uma dimensão específica considerando várias datas.
            
            :param dimension_name: Nome da dimensão (e.g., 'Grupo', 'Subgrupo').
            :param dimension_value: Valor da dimensão (e.g., 'Alimentação no Domicílio').
            :return: DataFrame com a série de variação m/m da dimensão.
            """
            # Filtrar os subitens da dimensão
            filtered_items = self.dimensions[self.dimensions[dimension_name] == dimension_value]
            filtered_data = self.data[self.data['Subitem'].isin(filtered_items['Subitem'])]
            filtered_weights = self.weights[self.weights['Subitem'].isin(filtered_items['Subitem'])]
            
            # Combinar os dados e pesos
            combined = filtered_data.merge(filtered_weights, on=['Subitem', 'dt'])
            
            # Reponderar os pesos por data
            combined['Peso_Reponderado'] = combined.groupby('dt')['Peso'].transform(lambda x: x / x.sum())
            
            # Calcular a contribuição de cada subitem
            combined['Contribuição'] = combined['var_mensal'] * combined['Peso_Reponderado']
            
            # Agregar as contribuições para obter a variação da dimensão
            dimension_variation = (
                combined.groupby('dt')['Contribuição']
                .sum()
                .reset_index(name='var_mensal_dimensão')
            )
            
            return dimension_variation

